(function(){
  const j="data:image/jpeg;base64,", p="data:image/png;base64,";
  document.getElementById('dl-logo').src=p+"";
  const si=(id,b,isP,w,h)=>{const e=document.getElementById(id);if(!e)return;e.src=(isP?p:j)+b;if(w)e.style.cssText=`width:${w}px;height:${h}px;border-radius:7px;object-fit:cover;flex-shrink:0`;};
  si('mi-ribs',"",false,60,49);
  si('mi-bife',"",false,60,49);
  si('mi-bac',"",false,60,49);
  si('li-pao',"",false,52,42);
  si('li-ribs',"",false,52,42);
  si('li-bac',"",false,52,42);
})();
const STEPS=[
  {l:'Largo Sao Domingos - Lisboa',h:'O cliente abre o menu em segundos.',p:'A carta abre automaticamente no idioma do telemovel ao ler o QR code - sem instalacao, sem configuracao.',hint:'Toque na bandeira para ver os idiomas'},
  {l:'24+ idiomas automaticos',h:'A carta no idioma do cliente - sem fazer nada.',p:'Portugues, ingles, espanhol, frances, arabe, mandarin e mais 18. O cliente nao precisa de selecionar nada.',hint:'Toque em Portugues para continuar'},
  {l:'Passo 1 - Couvert em video',h:'Pao com azeite. Ver e desejar.',p:'O cliente ve o pao artesanal com o azeite a ser vertido. Ja nao e uma linha de texto - e apetite imediato.',hint:'Toque em Add para adicionar'},
  {l:'Passo 2 - Entradas em video',h:'Salmao curado e fumado.',p:'O fumo a subir, as texturas, o empratamento. O cliente decide em segundos.',hint:'Toque em Add'},
  {l:'Passo 3 - Pratos principais',h:'Ribs de porco iberico em molho.',p:'Pratos mais caros, mais bem apresentados. O video justifica o preco.',hint:'Toque em Add'},
  {l:'Passo 4 - Mais pratos em video',h:'Lombo de Bacalhau com acorda cremosa.',p:'A carta continua. Cada categoria tem os seus videos. Toque em Menu.',hint:'Toque em Menu na nav bar'},
  {l:'Passo 5 - Vista de menu',h:'A carta completa, organizada.',p:'Vista lista com videos reais de cada prato, precos e descricoes.',hint:'Toque no Bife de novilho'},
  {l:'Passo 6 - Minha lista',h:'O pedido organizado, pronto a passar ao staff.',p:'Quando estiver pronto, chama o empregado com a lista completa.',hint:'Toque em Pronto'},
  {l:'Demo concluida',h:'E exatamente isto que os seus clientes vivem.',p:'Carta em 24h, videos em 7 dias, 24+ idiomas automaticos.',hint:null},
];
const SCS=[1,2,3,4,5,6,7,8,9].map(i=>document.getElementById('ds'+i));
const dside=document.getElementById('dside');
const dprog=document.getElementById('dprog');
const dlbl=document.getElementById('dlbl');
const dh=document.getElementById('dh');
const dp=document.getElementById('dp');
const dhint=document.getElementById('dhint');
const dhintt=document.getElementById('dhintt');
const drebtn=document.getElementById('drebtn');
let cur=0;
for(let i=0;i<8;i++){const s=document.createElement('div');s.className='ds-seg';dprog.appendChild(s);}
function setSide(i){
  dside.classList.add('fading');
  setTimeout(()=>{
    const d=STEPS[i];
    dlbl.textContent=d.l;dh.textContent=d.h;dp.textContent=d.p;
    dhint.style.display=d.hint?'inline-flex':'none';
    if(d.hint)dhintt.textContent=d.hint;
    drebtn.style.display=i===8?'block':'none';
    [...dprog.children].forEach((s,idx)=>s.classList.toggle('done',idx<i));
    dside.classList.remove('fading');
  },200);
}
function goTo(i){SCS[cur].classList.remove('on');cur=i;SCS[cur].classList.add('on');setSide(i);}
function toast(id,cb){const t=document.getElementById(id);if(t){t.classList.add('on');setTimeout(()=>{t.classList.remove('on');if(cb)cb();},1000);}}
function restart(){goTo(0);}
document.getElementById('tap-flag').addEventListener('click',()=>{if(cur===0)goTo(1);});
document.getElementById('tap-lang-pt').addEventListener('click',()=>{if(cur===1)goTo(2);});
document.getElementById('tap-comida').addEventListener('click',()=>{if(cur===0)goTo(1);});
document.getElementById('tap-add-pao').addEventListener('click',e=>{e.stopPropagation();if(cur===2)toast('t-pao',()=>goTo(3));});
document.getElementById('tap-add-salmao').addEventListener('click',e=>{e.stopPropagation();if(cur===3)toast('t-salmao',()=>goTo(4));});
document.getElementById('tap-add-ribs').addEventListener('click',e=>{e.stopPropagation();if(cur===4)toast('t-ribs',()=>goTo(5));});
document.getElementById('tap-add-bac').addEventListener('click',e=>{e.stopPropagation();if(cur===5)goTo(6);});
document.getElementById('ds6').querySelector('.app-nav').addEventListener('click',e=>{if(cur===5){const t=e.target.closest('.ni');if(t&&t.textContent.includes('Menu'))goTo(6);}});
document.getElementById('tap-bife').addEventListener('click',()=>{if(cur===6)goTo(7);});
document.getElementById('tap-fim').addEventListener('click',()=>{if(cur===7)goTo(8);});
document.getElementById('credo').addEventListener('click',restart);
drebtn.addEventListener('click',restart);
setSide(0);
